  v_area_ucv_razonamiento_logico UUID;
  v_area_ucv_razonamiento_verbal UUID;
  v_ucv_razonamiento_logico_relaciones_numericas UUID;
  v_ucv_razonamiento_logico_series_y_analogias_numericas UUID;
  v_ucv_razonamiento_logico_deduccion_y_problemas_de_logica UUID;
  v_ucv_razonamiento_logico_ordenamiento_de_informacion UUID;
  v_ucv_razonamiento_verbal_acentuacion_y_puntuacion UUID;
  v_ucv_razonamiento_verbal_analogias_verbales UUID;
  v_ucv_razonamiento_verbal_ordenacion_logica_de_parrafos UUID;
  v_ucv_razonamiento_verbal_vocabulario_y_significado_en_contexto UUID;
BEGIN

  -- ============================================================
  -- Universidades: obtener existentes o crear si no existen
  -- ============================================================
  INSERT INTO universities (code, name) VALUES ('simadi', 'Universidad Central de Venezuela (SIMADI)')
    ON CONFLICT (code) DO NOTHING;
  SELECT id INTO v_uni_ucv FROM universities WHERE code = 'simadi';

  -- ============================================================
  -- Areas: obtener existentes o crear si no existen
  -- ============================================================
  INSERT INTO areas (university_id, code, name) VALUES (v_uni_ucv, 'logico', 'Razonamiento logico')
    ON CONFLICT (university_id, code) DO NOTHING;
  SELECT id INTO v_area_ucv_razonamiento_logico FROM areas WHERE university_id = v_uni_ucv AND code = 'logico';

  INSERT INTO areas (university_id, code, name) VALUES (v_uni_ucv, 'verbal', 'Razonamiento verbal')
    ON CONFLICT (university_id, code) DO NOTHING;
  SELECT id INTO v_area_ucv_razonamiento_verbal FROM areas WHERE university_id = v_uni_ucv AND code = 'verbal';

  -- ============================================================
  -- Subtemas: crear/actualizar (idempotente)
  -- ============================================================
  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_logico, 'relaciones_numericas', 'Relaciones numericas', 'Relaciones numericas', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_logico_relaciones_numericas FROM subtopics WHERE area_id = v_area_ucv_razonamiento_logico AND code = 'relaciones_numericas';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_logico, 'series_y_analogias_numericas', 'Series y analogias numericas', 'Series y analogias numericas', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_logico_series_y_analogias_numericas FROM subtopics WHERE area_id = v_area_ucv_razonamiento_logico AND code = 'series_y_analogias_numericas';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_logico, 'deduccion_y_problemas_de_logica', 'Deduccion y problemas de logica', 'Deduccion y problemas de logica', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_logico_deduccion_y_problemas_de_logica FROM subtopics WHERE area_id = v_area_ucv_razonamiento_logico AND code = 'deduccion_y_problemas_de_logica';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_logico, 'ordenamiento_de_informacion', 'Ordenamiento de informacion', 'Ordenamiento de informacion', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_logico_ordenamiento_de_informacion FROM subtopics WHERE area_id = v_area_ucv_razonamiento_logico AND code = 'ordenamiento_de_informacion';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_verbal, 'acentuacion_y_puntuacion', 'Acentuacion y puntuacion', 'Acentuacion y puntuacion', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_verbal_acentuacion_y_puntuacion FROM subtopics WHERE area_id = v_area_ucv_razonamiento_verbal AND code = 'acentuacion_y_puntuacion';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_verbal, 'analogias_verbales', 'Analogias verbales', 'Analogias verbales', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
