    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_verbal_ordenacion_logica_de_parrafos FROM subtopics WHERE area_id = v_area_ucv_razonamiento_verbal AND code = 'ordenacion_logica_de_parrafos';

  INSERT INTO subtopics (area_id, code, name, description, difficulty_weight)
    VALUES (v_area_ucv_razonamiento_verbal, 'vocabulario_y_significado_en_contexto', 'Vocabulario y significado en contexto', 'Vocabulario y significado en contexto', 1.0)
    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_ucv_razonamiento_verbal_vocabulario_y_significado_en_contexto FROM subtopics WHERE area_id = v_area_ucv_razonamiento_verbal AND code = 'vocabulario_y_significado_en_contexto';

  -- ============================================================
  -- INSERCION DE 197 PREGUNTAS
  -- ============================================================
  INSERT INTO questions (subtopic_id, university_id, area_id, statement, options, correct_answer, explanation, difficulty, source_type, source_reference) VALUES
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un comerciante compra un producto en 50 Bs. y lo vende con una ganancia del 20% sobre el precio de compra. ¿A qué precio lo vende?', '{"A": "55", "B": "65", "C": "70", "D": "60"}', 'D', 'El 20% de 50 es 10, por lo que el precio de venta es 50+10=60.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 242)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'La razón entre las edades de Ulises y Camila es 4:5. Si Ulises tiene 16 años, ¿cuántos años tiene Camila?', '{"A": "17", "B": "16", "C": "25", "D": "20"}', 'D', 'Si la razón es 4:5 y Ulises (4 partes) tiene 16 años, cada parte equivale a 16÷4=4 años. Camila (5 partes) tiene 5×4=20 años.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 243)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Gabriela obtuvo las siguientes notas en 4 exámenes: 10, 20, 17, 20. ¿Qué nota necesita en un examen más para que el promedio final de los 5 exámenes sea 14?', '{"A": "3", "B": "5", "C": "67", "D": "1"}', 'A', 'La suma de las 4 notas es 67. Para un promedio de 14 en 5 notas, la suma total debe ser 14×5=70. La nota faltante es 70−67=3.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 244)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, '5 obreros terminan una siembra del terreno en 12 días. Si se contratan 3 obreros más (manteniendo el mismo rendimiento por obrero), ¿en cuántos días aproximadamente terminarían la misma tarea?', '{"A": "4.5", "B": "12", "C": "9.5", "D": "7.5"}', 'D', 'El trabajo total es 5×12=60 obrero-días. Con 8 obreros: 60÷8=7.5 días.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 245)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un artículo cuesta 200 Bs. y tiene un descuento del 30%. ¿Cuánto se paga por el artículo?', '{"A": "140", "B": "60", "C": "150", "D": "130"}', 'A', 'El descuento es 200×30%=60 Bs. Precio final: 200−60=140 Bs.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 246)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'En una encuesta, 7 de cada 12 personas prefieren café sobre té. Si se encuestó a 480 personas en total, ¿cuántas prefieren té?', '{"A": "200", "B": "480", "C": "280", "D": "210"}', 'A', 'Si 7 de cada 12 prefieren café, entonces 5 de cada 12 prefieren té, es decir 5/12 del total. (5/12)×480=200.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 247)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un comerciante compra un producto en 50 Bs. y lo vende con una ganancia del 25% sobre el precio de compra. ¿A qué precio lo vende?', '{"A": "57", "B": "67", "C": "62", "D": "75"}', 'C', 'El 25% de 50 es 12, por lo que el precio de venta es 50+12=62.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 248)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'La razón entre las edades de Nestor y Tatiana es 4:7. Si Nestor tiene 24 años, ¿cuántos años tiene Tatiana?', '{"A": "47", "B": "42", "C": "39", "D": "24"}', 'B', 'Si la razón es 4:7 y Nestor (4 partes) tiene 24 años, cada parte equivale a 24÷4=6 años. Tatiana (7 partes) tiene 7×6=42 años.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 249)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, '3 obreros terminan una construcción de un muro en 20 días. Si se contratan 3 obreros más (manteniendo el mismo rendimiento por obrero), ¿en cuántos días aproximadamente terminarían la misma tarea?', '{"A": "12.0", "B": "20", "C": "10.0", "D": "7.0"}', 'C', 'El trabajo total es 3×20=60 obrero-días. Con 6 obreros: 60÷6=10.0 días.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 250)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un artículo cuesta 250 Bs. y tiene un descuento del 10%. ¿Cuánto se paga por el artículo?', '{"A": "225", "B": "235", "C": "215", "D": "25"}', 'A', 'El descuento es 250×10%=25 Bs. Precio final: 250−25=225 Bs.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 251)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'En una encuesta, 11 de cada 12 personas prefieren refresco sobre jugo. Si se encuestó a 480 personas en total, ¿cuántas prefieren jugo?', '{"A": "40", "B": "440", "C": "480", "D": "50"}', 'A', 'Si 11 de cada 12 prefieren refresco, entonces 1 de cada 12 prefieren jugo, es decir 1/12 del total. (1/12)×480=40.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 252)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un comerciante compra un producto en 120 Bs. y lo vende con una ganancia del 25% sobre el precio de compra. ¿A qué precio lo vende?', '{"A": "150", "B": "145", "C": "146", "D": "155"}', 'A', 'El 25% de 120 es 30, por lo que el precio de venta es 120+30=150.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 253)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'La razón entre las edades de Oriana y Rosa es 1:2. Si Oriana tiene 8 años, ¿cuántos años tiene Rosa?', '{"A": "13", "B": "16", "C": "21", "D": "8"}', 'B', 'Si la razón es 1:2 y Oriana (1 partes) tiene 8 años, cada parte equivale a 8÷1=8 años. Rosa (2 partes) tiene 2×8=16 años.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 254)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, '6 obreros terminan una pintura de un galpón en 15 días. Si se contratan 3 obreros más (manteniendo el mismo rendimiento por obrero), ¿en cuántos días aproximadamente terminarían la misma tarea?', '{"A": "10.0", "B": "7.0", "C": "15", "D": "12.0"}', 'A', 'El trabajo total es 6×15=90 obrero-días. Con 9 obreros: 90÷9=10.0 días.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 255)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un artículo cuesta 200 Bs. y tiene un descuento del 25%. ¿Cuánto se paga por el artículo?', '{"A": "50", "B": "150", "C": "160", "D": "140"}', 'B', 'El descuento es 200×25%=50 Bs. Precio final: 200−50=150 Bs.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 256)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'En una encuesta, 9 de cada 12 personas prefieren café sobre té. Si se encuestó a 600 personas en total, ¿cuántas prefieren té?', '{"A": "160", "B": "150", "C": "450", "D": "600"}', 'B', 'Si 9 de cada 12 prefieren café, entonces 3 de cada 12 prefieren té, es decir 3/12 del total. (3/12)×600=150.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 257)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un comerciante compra un producto en 80 Bs. y lo vende con una ganancia del 35% sobre el precio de compra. ¿A qué precio lo vende?', '{"A": "103", "B": "113", "C": "108", "D": "115"}', 'C', 'El 35% de 80 es 28, por lo que el precio de venta es 80+28=108.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 258)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'La razón entre las edades de Tatiana y Samuel es 1:2. Si Tatiana tiene 7 años, ¿cuántos años tiene Samuel?', '{"A": "19", "B": "7", "C": "11", "D": "14"}', 'D', 'Si la razón es 1:2 y Tatiana (1 partes) tiene 7 años, cada parte equivale a 7÷1=7 años. Samuel (2 partes) tiene 2×7=14 años.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 259)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, '5 obreros terminan una reparación de la maquinaria en 20 días. Si se contratan 3 obreros más (manteniendo el mismo rendimiento por obrero), ¿en cuántos días aproximadamente terminarían la misma tarea?', '{"A": "14.5", "B": "9.5", "C": "12.5", "D": "20"}', 'C', 'El trabajo total es 5×20=100 obrero-días. Con 8 obreros: 100÷8=12.5 días.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 260)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un artículo cuesta 600 Bs. y tiene un descuento del 30%. ¿Cuánto se paga por el artículo?', '{"A": "430", "B": "420", "C": "410", "D": "180"}', 'B', 'El descuento es 600×30%=180 Bs. Precio final: 600−180=420 Bs.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 261)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'En una encuesta, 11 de cada 8 personas prefieren refresco sobre chocolate. Si se encuestó a 400 personas en total, ¿cuántas prefieren chocolate?', '{"A": "400", "B": "550", "C": "-150", "D": "-140"}', 'C', 'Si 11 de cada 8 prefieren refresco, entonces -3 de cada 8 prefieren chocolate, es decir -3/8 del total. (-3/8)×400=-150.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 262)'),
    (v_ucv_razonamiento_logico_relaciones_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Un comerciante compra un producto en 60 Bs. y lo vende con una ganancia del 15% sobre el precio de compra. ¿A qué precio lo vende?', '{"A": "69", "B": "74", "C": "75", "D": "64"}', 'A', 'El 15% de 60 es 9, por lo que el precio de venta es 60+9=69.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Relaciones numericas (id_original 263)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 13, 17, 21, 25, 29, ___', '{"A": "30", "B": "33", "C": "37", "D": "34"}', 'B', 'Cada término aumenta 4 respecto al anterior. El siguiente término es 29+4=33.', 'easy', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 264)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 2, 6, 18, 54, 162, ___', '{"A": "389", "B": "489", "C": "484", "D": "486"}', 'D', 'Cada término se multiplica por 3 respecto al anterior. El siguiente término es 162×3=486.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 265)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 9, 16, 25, 36, 49, ___', '{"A": "63", "B": "49", "C": "64", "D": "72"}', 'C', 'Cada término sigue el patrón elevar al cuadrado (n²), con n = 3,4,...,8. El siguiente término es 8²=64.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 266)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 9, 14, 21, 30, 41, ___', '{"A": "54", "B": "42", "C": "52", "D": "57"}', 'A', 'Diferencias sucesivas: 5, 7, 9, 11, 13. El siguiente término es 41+13=54. Las diferencias forman una progresión aritmética con razón 2.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 267)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 2, 6, 12, 20, 30, ___', '{"A": "44", "B": "42", "C": "40", "D": "35"}', 'B', 'Cada término sigue el patrón n×(n+1), con n = 1,2,...,6. El siguiente término es 6×7=42.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 268)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 1, 8, 27, 64, ___', '{"A": "125", "B": "135", "C": "100", "D": "115"}', 'A', 'Cada término sigue el patrón elevar al cubo (n³), con n = 1,...,5. El siguiente término es 5³=125.', 'hard', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 269)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 8, 13, 18, 23, 28, ___', '{"A": "38", "B": "34", "C": "29", "D": "33"}', 'D', 'Cada término aumenta 5 respecto al anterior. El siguiente término es 28+5=33.', 'easy', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 270)'),
    (v_ucv_razonamiento_logico_series_y_analogias_numericas, v_uni_ucv, v_area_ucv_razonamiento_logico, 'Complete la secuencia: 2, 4, 8, 16, 32, ___', '{"A": "62", "B": "51", "C": "64", "D": "66"}', 'C', 'Cada término se multiplica por 2 respecto al anterior. El siguiente término es 32×2=64.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Series y analogias numericas (id_original 271)'),
