    (v_ucv_razonamiento_verbal_acentuacion_y_puntuacion, v_uni_ucv, v_area_ucv_razonamiento_verbal, 'Seleccione la oración con correcta acentuación y puntuación:', '{"A": "El niño, que llegó tarde, se disculpó con el profesor.", "B": "El niño que llegó tarde se disculpó, con el profesor.", "C": "El niño que llegó tarde, se disculpó con el profesor.", "D": "El niño, que llegó tarde se disculpó con el profesor."}', 'A', 'La coma encierra una aposición explicativa (''que llegó tarde''). Las demás opciones alteran el sentido con puntuación incorrecta.', 'easy', 'generated_pattern', 'Patron UCV SIMADI - Acentuacion y puntuacion (id_original 339)'),
    (v_ucv_razonamiento_verbal_acentuacion_y_puntuacion, v_uni_ucv, v_area_ucv_razonamiento_verbal, 'Seleccione la oración con correcta acentuación y puntuación:', '{"A": "Sí, mi hermano vendrá mañana temprano.", "B": "Si, mi hermano vendrá mañana temprano.", "C": "Sí mi hermano, vendrá mañana temprano.", "D": "Si mi hermano vendrá, mañana temprano."}', 'A', '''Sí'' con tilde es el adverbio de afirmación, seguido de coma. Las demás opciones tienen errores de tilde o de puntuación.', 'medium', 'generated_pattern', 'Patron UCV SIMADI - Acentuacion y puntuacion (id_original 340)'),
