    ON CONFLICT (area_id, code) DO UPDATE SET name = EXCLUDED.name;
  SELECT id INTO v_unimet_aptitud_verbal_relaciones_analogicas FROM subtopics WHERE area_id = v_area_unimet_aptitud_verbal AND code = 'relaciones_analogicas';

  -- ============================================================
  -- INSERCION DE 200 PREGUNTAS
  -- ============================================================
  INSERT INTO questions (subtopic_id, university_id, area_id, statement, options, correct_answer, explanation, difficulty, source_type, source_reference) VALUES
    (v_unimet_aptitud_cuantitativa_estimacion_y_calculo_proporcional, v_uni_unimet, v_area_unimet_aptitud_cuantitativa, 'Si un libro tiene 384 páginas y lo lees 24 páginas por día, ¿aproximadamente en cuántos días lo terminas?', '{"A": "16 días", "B": "13 días", "C": "24 días", "D": "20 días"}', 'A', '384/24≈16.0, es decir, aproximadamente 16 días.', 'easy', 'generated_pattern', 'Patron UNIMET PDU - Estimacion y calculo proporcional (id_original 439)'),
    (v_unimet_aptitud_cuantitativa_estimacion_y_calculo_proporcional, v_uni_unimet, v_area_unimet_aptitud_cuantitativa, 'Si 2 máquinas producen 100 piezas en 4 horas, ¿cuántas piezas producen 5 máquinas en 5 horas (con el mismo rendimiento por máquina)?', '{"A": "332", "B": "250", "C": "282", "D": "312"}', 'D', 'Producción por máquina por hora = 100/(2×4)=12. 5 máquinas en 5 horas: 5×5×12=312.', 'medium', 'generated_pattern', 'Patron UNIMET PDU - Estimacion y calculo proporcional (id_original 440)'),
    (v_unimet_aptitud_cuantitativa_estimacion_y_calculo_proporcional, v_uni_unimet, v_area_unimet_aptitud_cuantitativa, 'Un tanque se llena con 3 grifos iguales en 10 horas. Si se abren 4 grifos iguales, ¿en cuántas horas se llena?', '{"A": "4.5 horas", "B": "9.5 horas", "C": "7.5 horas", "D": "10 horas"}', 'C', 'Trabajo total = 3×10=30 grifo-horas. Con 4 grifos: 30/4=7.5 horas.', 'medium', 'generated_pattern', 'Patron UNIMET PDU - Estimacion y calculo proporcional (id_original 441)'),
