    (v_unimet_aptitud_verbal_ortografia, v_uni_unimet, v_area_unimet_aptitud_verbal, '¿Cuál oración está escrita correctamente?', '{"A": "El equipo obtuvo excelentes resultados en la competencia.", "B": "El equipo obtubo excelentes resultados en la competencia.", "C": "El equipo optuvo excelentes resultados en la competencia.", "D": "El equipo obtuvo exelentes resultados en la competencia."}', 'A', '''Obtuvo'' se escribe con v (del verbo obtener), y ''excelentes'' lleva x. La opción A está correctamente escrita.', 'medium', 'generated_pattern', 'Patron UNIMET PDU - Ortografia (id_original 573)'),
    (v_unimet_aptitud_verbal_ortografia, v_uni_unimet, v_area_unimet_aptitud_verbal, '¿Cuál oración está escrita correctamente?', '{"A": "Es probable que la reunión se posponga para el viernes.", "B": "Es probable que la reunión se pospoga para el viernes.", "C": "Es probable que la reunión se postponga para el viernes.", "D": "Es provable que la reunión se posponga para el viernes."}', 'A', '''Pospone/posponga'' se escribe sin t y con una sola s, del verbo posponer. ''Probable'' se escribe con b.', 'medium', 'generated_pattern', 'Patron UNIMET PDU - Ortografia (id_original 574)'),
